const orgDoc = $('Find Organization and intents').first().json;
const rawPhone = $('Execute Workflow Trigger').first().json.phoneNumber || "";

// Consider it an auth intent if it has a formId AND EITHER a fieldName OR a numberField
const authIntents = (orgDoc.intents || []).filter(i => i.auth && i.auth.formId && (i.auth.fieldName || i.auth.numberField));

if (authIntents.length === 0) {
  return [{ json: { ...orgDoc, needsAuthFilter: false } }];
}

// Strip non-digits and get last 10
const cleanPhone = String(rawPhone).replace(/\D/g, '');
const baseNum = cleanPhone.length > 10 ? cleanPhone.slice(-10) : cleanPhone;

const camelCase = (str) => {
  if (!str) return '';
  return str.replace(/(?:^\w|[A-Z]|\b\w)/g, (word, index) => {
    return index === 0 ? word.toLowerCase() : word.toUpperCase();
  }).replace(/\s+/g, '');
};

const orConditions = authIntents.map(i => {
  const f1 = i.auth.fieldName || i.auth.numberField;
  const f2 = camelCase(f1);

  // Use "contains" instead of "ends with" to be safe against trailing whitespace
  const regexQuery = { "$regex": baseNum, "$options": "i" };

  const fieldOrs = [
    { [f1]: regexQuery },
    { [f1 + ".value"]: regexQuery }
  ];

  if (f1 !== f2) {
    fieldOrs.push({ [f2]: regexQuery }, { [f2 + ".value"]: regexQuery });
  }

  return {
    "formid": i.auth.formId,
    "$or": fieldOrs
  };
});

const query = { "$or": orConditions };
return [{ json: { ...orgDoc, needsAuthFilter: true, authQuery: query } }];

// Deep clone to prevent mutating original cached data
const orgDoc = JSON.parse(JSON.stringify($('Find Organization and intents').first().json));

const needs = $('Build Auth Filter Query').first().json.needsAuthFilter;
let authorizedFormIds = [];

if (needs) {
  // If needs is true, this node was reached via 'Fetch Authorized Forms', 
  // meaning $input contains the DDF values returned by the database.
  const ddfValues = $input.all().map(item => item.json);
  authorizedFormIds = ddfValues.map(doc => doc.formid).filter(id => id);
}

const filteredIntents = (orgDoc.intents || []).filter(i => {
  // Disabled intents (isActive === false, set via the Intent Builder toggle)
  // are invisible to the chatbot entirely — filtered here so every downstream
  // consumer (welcome buttons, the LLM's available-intents list, execution
  // lookup) automatically respects it without separate changes.
  if (i.isActive === false) return false;
  if (!i.auth || !i.auth.formId) return true;
  return authorizedFormIds.includes(i.auth.formId);
});

orgDoc.intents = filteredIntents;
